import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { obtenerProductos } from '../services/productoService';
import { registrarVenta } from '../services/ventaService';

const Ventas = () => {
    const navigate = useNavigate();
    const [productos, setProductos] = useState([]);
    const [carrito, setCarrito] = useState({
        productoId: '', codigo: '', nombre: '', precio: 0, cantidad: 1, stockDisponible: 0
    });
    const [pago, setPago] = useState({ efectivo: 0, cambio: 0 });
    const [ventaRealizada, setVentaRealizada] = useState(null);

    useEffect(() => {
        if (!localStorage.getItem('usuarioLogueado')) {
            navigate("/");
        } else {
            obtenerProductos().then(setProductos);
        }
    }, [navigate]);

    // Cálculo de cambio en tiempo real
    useEffect(() => {
        const total = carrito.precio * carrito.cantidad;
        setPago(prev => ({ ...prev, cambio: prev.efectivo > 0 ? prev.efectivo - total : 0 }));
    }, [pago.efectivo, carrito.precio, carrito.cantidad]);

    const seleccionarProducto = (e) => {
        const prod = productos.find(p => p.id.toString() === e.target.value);
        if (prod) {
            setCarrito({
                productoId: prod.id, codigo: prod.codigo, nombre: prod.nombre,
                precio: prod.precioVenta, cantidad: 1, stockDisponible: prod.stock
            });
        }
    };

    const handleVenta = async (e) => {
        e.preventDefault();
        const totalVenta = carrito.precio * carrito.cantidad;

        if (pago.efectivo < totalVenta) return alert("❌ Efectivo insuficiente");

        const datos = {
            codigoProducto: carrito.codigo,
            nombreProducto: carrito.nombre,
            cantidad: carrito.cantidad,
            precioVenta: carrito.precio,
            vendedorMatricula: localStorage.getItem('usuarioLogueado')
        };

        const resultado = await registrarVenta(datos);
        if (resultado) {
            setVentaRealizada({ ...resultado, efectivo: pago.efectivo, cambio: pago.cambio });
            // El alert ahora es opcional porque ya verás el ticket en pantalla
            setTimeout(() => {
                window.print();
                setVentaRealizada(null); // Limpiar para nueva venta tras imprimir
                setCarrito({ productoId: '', codigo: '', nombre: '', precio: 0, cantidad: 1, stockDisponible: 0 });
                setPago({ efectivo: 0, cambio: 0 });
            }, 800);
        }
    };

    return (
        <div style={{ padding: '30px', fontFamily: 'Arial', maxWidth: '900px', margin: '0 auto' }}>
            <div className="no-print">
                <h2 style={{ textAlign: 'center', color: '#007bff' }}>🚀 Punto de Venta - Isla Tecnológica</h2>
                
                <div style={{ display: 'grid', gridTemplateColumns: '1.5fr 1fr', gap: '20px' }}>
                    {/* FORMULARIO DE COBRO */}
                    <div style={{ background: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 15px rgba(0,0,0,0.1)' }}>
                        <form onSubmit={handleVenta}>
                            <label><b>Producto</b></label>
                            <select onChange={seleccionarProducto} style={{ width: '100%', padding: '12px', margin: '10px 0', borderRadius: '8px' }} required>
                                <option value="">-- Buscar Producto --</option>
                                {productos.map(p => <option key={p.id} value={p.id}>{p.nombre} ({p.codigo})</option>)}
                            </select>

                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px' }}>
                                <input type="number" placeholder="Cant" min="1" value={carrito.cantidad} onChange={e => setCarrito({...carrito, cantidad: e.target.value})} style={{ padding: '10px', borderRadius: '8px' }} />
                                <input type="number" placeholder="Precio $" value={carrito.precio} onChange={e => setCarrito({...carrito, precio: e.target.value})} style={{ padding: '10px', borderRadius: '8px', border: '2px solid #007bff' }} />
                            </div>

                            <div style={{ marginTop: '20px', borderTop: '2px dashed #eee', paddingTop: '20px' }}>
                                <label><b>Paga con:</b></label>
                                <input type="number" value={pago.efectivo} onChange={e => setPago({...pago, efectivo: e.target.value})} style={{ width: '100%', padding: '15px', fontSize: '20px', borderRadius: '8px', marginTop: '5px' }} />
                            </div>

                            <button type="submit" style={{ width: '100%', padding: '15px', background: '#28a745', color: '#fff', border: 'none', borderRadius: '8px', marginTop: '20px', fontWeight: 'bold', fontSize: '18px', cursor: 'pointer' }}>
                                ✅ COBRAR E IMPRIMIR
                            </button>
                        </form>
                    </div>

                    {/* VISTA PREVIA DEL TICKET (Digital) */}
                    <div style={{ background: '#e9ecef', padding: '15px', borderRadius: '12px', border: '1px solid #ccc' }}>
                        <h4 style={{ textAlign: 'center', margin: '0' }}>Vista Previa Ticket</h4>
                        <div style={{ background: '#fff', padding: '15px', marginTop: '10px', minHeight: '300px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)', fontSize: '13px' }}>
                            <center><b>ISLA TECNOLÓGICA</b></center>
                            <hr/>
                            <p>Art: {carrito.nombre || '---'}</p>
                            <p>Cant: {carrito.cantidad} x ${carrito.precio}</p>
                            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '18px', fontWeight: 'bold' }}>
                                <span>TOTAL:</span> <span>${(carrito.precio * carrito.cantidad).toFixed(2)}</span>
                            </div>
                            <hr/>
                            <p>Cambio: <span style={{ color: 'blue' }}>${pago.cambio.toFixed(2)}</span></p>
                        </div>
                    </div>
                </div>
            </div>

            {/* TICKET FÍSICO (Solo se ve al imprimir) */}
            {ventaRealizada && (
                <div className="print-only" style={{ width: '80mm', padding: '5mm', fontFamily: 'monospace' }}>
                    <center>
                        <h2 style={{ margin: '0' }}>ISLA TECNOLÓGICA</h2>
                        <p style={{ margin: '0' }}>Sucursal: Morelos 401-A</p>
                        <p style={{ margin: '0' }}>Aguascalientes, México</p>
                        <p>Tel: 449-512-9849</p>
                        <p>--------------------------------</p>
                    </center>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <span>Venta: {ventaRealizada.id}</span>
                        <span>{new Date().toLocaleDateString()}</span>
                    </div>
                    <p>Atendido por: {ventaRealizada.vendedorMatricula}</p>
                    <p>--------------------------------</p>
                    <div>
                        <span>{ventaRealizada.cantidad} x {ventaRealizada.nombreProducto}</span>
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <span>${ventaRealizada.precioVenta.toFixed(2)}</span>
                            <span>${ventaRealizada.total.toFixed(2)}</span>
                        </div>
                    </div>
                    <p>--------------------------------</p>
                    <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold' }}>
                        <span>TOTAL:</span> <span>MXN: ${ventaRealizada.total.toFixed(2)}</span>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <span>Efectivo:</span> <span>${ventaRealizada.efectivo}</span>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <span>Cambio:</span> <span>${ventaRealizada.cambio.toFixed(2)}</span>
                    </div>
                    <center style={{ marginTop: '15px' }}>
                        <p>¡Gracias por su preferencia!</p>
                        <p style={{ fontSize: '10px' }}>{ventaRealizada.id}-{Math.random().toString(36).substr(2, 5)}</p>
                    </center>
                </div>
            )}
        </div>
    );
};

export default Ventas;
